-- bab: hajimemashite (はじめまして)
insert into public.lingbook_chapters (book_id,slug,label,title,subtitle,meta,glossary,blocks,steps,objectives,vocab_refs,grammar_points,exercises,test,roleplay,sort,published) select b.id,'hajimemashite','Unit 1 — はじめまして','はじめまして','Perkenalan','± 12 menit · dialog + 4 grammar points + latihan',$lb${"hajimemashite":{"surface":"はじめまして","romaji":"hajimemashite","meaning":"salam kenal; perkenalkan","pos":"ungkapan","grammar":{"Konteks":"diucapkan saat pertama kali bertemu","Arti harfiah":"\"untuk pertama kalinya\""}},"watashi":{"surface":"私","reading":"わたし","romaji":"watashi","meaning":"saya","pos":"pronomina","grammar":{"Register":"netral, bisa formal","Peran":"topik"}},"ha":{"surface":"は","romaji":"wa","meaning":"penanda topik","pos":"partikel","grammar":{"Fungsi":"menandai topik kalimat","Catatan":"ditulis は, dibaca \"wa\"","Kalimat ini":"menandai siapa yang diperkenalkan"}},"desu":{"surface":"です","romaji":"desu","meaning":"kopula sopan (\"adalah\")","pos":"kopula","grammar":{"Fungsi":"mengakhiri kalimat dengan sopan","Bentuk":"non-lampau · positif"},"forms":[{"form":"でした","note":"lampau"},{"form":"じゃありません","note":"negatif sopan"}]},"anna":{"surface":"アンナ","romaji":"Anna","meaning":"Anna (nama orang)","pos":"nomina","grammar":{"Jenis":"nama diri (katakana)"}},"amerikajin":{"surface":"アメリカ人","reading":"アメリカじん","romaji":"Amerika-jin","meaning":"orang Amerika","pos":"nomina","grammar":{"Pola":"[negara] + 人 = warga negara","Kata dasar":"アメリカ = Amerika"}},"tanaka":{"surface":"田中","reading":"たなか","romaji":"Tanaka","meaning":"Tanaka (nama keluarga)","pos":"nomina","grammar":{"Jenis":"nama keluarga (umum di Jepang)"}},"kaishain":{"surface":"会社員","reading":"かいしゃいん","romaji":"kaishain","meaning":"karyawan; pegawai kantor","pos":"nomina","grammar":{"Kata dasar":"会社 = perusahaan","Peran":"predikat (pekerjaan)"}},"douzo":{"surface":"どうぞ","romaji":"dōzo","meaning":"silakan; mohon","pos":"adverbia","grammar":{"Fungsi":"memperhalus permintaan / persilaan"}},"yoroshiku":{"surface":"よろしく","romaji":"yoroshiku","meaning":"mohon bantuannya","pos":"ungkapan","grammar":{"Konteks":"harapan hubungan baik ke depan"}},"onegaishimasu":{"surface":"お願いします","reading":"おねがいします","romaji":"onegaishimasu","meaning":"mohon; tolong","pos":"ungkapan","grammar":{"Pola":"どうぞよろしくお願いします = salam kenalan lengkap","Tingkat sopan":"sopan-hormat"}},"san":{"surface":"さん","romaji":"-san","meaning":"sufiks hormat untuk nama","pos":"sufiks","grammar":{"Fungsi":"panggilan sopan, netral gender","Catatan":"jangan dipakai untuk diri sendiri"}},"nihonjin":{"surface":"日本人","reading":"にほんじん","romaji":"Nihon-jin","meaning":"orang Jepang","pos":"nomina","grammar":{"Kata dasar":"日本 = Jepang","Pola":"[negara] + 人"}},"ka":{"surface":"か","romaji":"ka","meaning":"partikel tanya","pos":"partikel","grammar":{"Fungsi":"mengubah kalimat menjadi pertanyaan","Catatan":"menggantikan tanda tanya"}},"hai":{"surface":"はい","romaji":"hai","meaning":"ya","pos":"ungkapan","grammar":{"Fungsi":"jawaban afirmatif"}},"iie":{"surface":"いいえ","romaji":"iie","meaning":"tidak","pos":"ungkapan","grammar":{"Fungsi":"jawaban negatif"}},"gakusei":{"surface":"学生","reading":"がくせい","romaji":"gakusei","meaning":"pelajar; mahasiswa","pos":"nomina","grammar":{"Peran":"predikat (status)"}},"namae":{"surface":"名前","reading":"なまえ","romaji":"namae","meaning":"nama","pos":"nomina"},"o":{"surface":"お","romaji":"o","meaning":"awalan hormat","pos":"prefiks","grammar":{"Fungsi":"memperhalus kata benda milik lawan bicara","Contoh":"お名前 = nama Anda"}},"no":{"surface":"の","romaji":"no","meaning":"partikel \"milik / punya\"","pos":"partikel","grammar":{"Fungsi":"menghubungkan dua nomina (kepemilikan)","Frasa ini":"私の名前 = namaku"}},"nan":{"surface":"何","reading":"なん","romaji":"nan","meaning":"apa","pos":"pronomina","grammar":{"Jenis":"kata tanya"}},"konnichiwa":{"surface":"こんにちは","romaji":"konnichiwa","meaning":"selamat siang; halo","pos":"ungkapan","grammar":{"Konteks":"sapaan siang hari"}},"indoneshiajin":{"surface":"インドネシア人","reading":"インドネシアじん","romaji":"Indoneshia-jin","meaning":"orang Indonesia","pos":"nomina","grammar":{"Pola":"[negara] + 人"}},"sensei":{"surface":"先生","reading":"せんせい","romaji":"sensei","meaning":"guru; pengajar","pos":"nomina","grammar":{"Catatan":"juga panggilan hormat untuk dokter/ahli"}},"isha":{"surface":"医者","reading":"いしゃ","romaji":"isha","meaning":"dokter","pos":"nomina"},"dewa":{"surface":"じゃありません","romaji":"ja arimasen","meaning":"bukan (negatif sopan)","pos":"kopula","grammar":{"Fungsi":"negatif dari です","Bentuk":"非-lampau · negatif"}}}$lb$::jsonb,$lb$[{"type":"heading","text":"会話の前に","sub":"Sebelum Percakapan"},{"type":"paragraph","tokens":[{"ref":"anna"},{"ref":"san"},{"ref":"ha"},{"ref":"amerikajin"},{"ref":"no"},{"ref":"gakusei"},{"ref":"desu"},{"text":"。"},{"ref":"tanaka"},{"ref":"san"},{"ref":"ha"},{"ref":"nihonjin"},{"ref":"no"},{"ref":"kaishain"},{"ref":"desu"},{"text":"。"}],"translation":"Anna adalah mahasiswa dari Amerika. Tanaka adalah pegawai kantor orang Jepang."},{"type":"heading","text":"会話","sub":"Percakapan"},{"type":"dialog","audioSrc":"/audio/lingbook/ja/hajimemashite/dialog.mp3","lines":[{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"hajimemashite"},{"text":"。"},{"ref":"watashi"},{"ref":"ha"},{"ref":"anna"},{"ref":"desu"},{"text":"。"}],"translation":"Salam kenal. Saya Anna.","audioSrc":"/audio/lingbook/ja/hajimemashite/l1.mp3"},{"speaker":"田中","role":"Tanaka","color":"#11313A","tokens":[{"ref":"hajimemashite"},{"text":"。"},{"ref":"tanaka"},{"ref":"desu"},{"text":"。"},{"ref":"douzo"},{"ref":"yoroshiku"},{"ref":"onegaishimasu"},{"text":"。"}],"translation":"Salam kenal. Saya Tanaka. Mohon bantuannya.","audioSrc":"/audio/lingbook/ja/hajimemashite/l2.mp3"},{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"tanaka"},{"ref":"san"},{"ref":"ha"},{"ref":"kaishain"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Apakah Tanaka-san pegawai kantor?","audioSrc":"/audio/lingbook/ja/hajimemashite/l3.mp3"},{"speaker":"田中","role":"Tanaka","color":"#11313A","tokens":[{"ref":"hai"},{"text":"、"},{"ref":"kaishain"},{"ref":"desu"},{"text":"。"},{"ref":"anna"},{"ref":"san"},{"ref":"ha"},{"ref":"gakusei"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Ya, saya pegawai kantor. Kalau Anna, mahasiswa?","audioSrc":"/audio/lingbook/ja/hajimemashite/l4.mp3"},{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"hai"},{"text":"、"},{"ref":"amerikajin"},{"ref":"no"},{"ref":"gakusei"},{"ref":"desu"},{"text":"。"}],"translation":"Ya, saya mahasiswa dari Amerika.","audioSrc":"/audio/lingbook/ja/hajimemashite/l5.mp3"}]},{"type":"audio","title":"Percakapan lengkap — kecepatan natural","src":"/audio/lingbook/ja/hajimemashite/full.mp3","durationSec":28,"transcript":[{"name":"Anna","tokens":[{"ref":"hajimemashite"},{"text":"。"},{"ref":"watashi"},{"ref":"ha"},{"ref":"anna"},{"ref":"desu"},{"text":"。"}]},{"name":"Tanaka","tokens":[{"ref":"hajimemashite"},{"text":"。"},{"ref":"tanaka"},{"ref":"desu"},{"text":"。"},{"ref":"douzo"},{"ref":"yoroshiku"},{"ref":"onegaishimasu"},{"text":"。"}]},{"name":"Anna","tokens":[{"ref":"tanaka"},{"ref":"san"},{"ref":"ha"},{"ref":"kaishain"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}]},{"name":"Tanaka","tokens":[{"ref":"hai"},{"text":"、"},{"ref":"kaishain"},{"ref":"desu"},{"text":"。"}]}]},{"type":"culture_note","title":"Budaya: 名刺 (meishi) & membungkuk","body":"Saat berkenalan formal di Jepang, orang saling menukar kartu nama (名刺) sambil sedikit membungkuk (お辞儀), bukan berjabat tangan. Terima kartu dengan dua tangan dan jangan langsung dimasukkan ke saku."}]$lb$::jsonb,$lb$[{"id":"tujuan","label":"Tujuan"},{"id":"dialog","label":"Dialog"},{"id":"vocab","label":"Kosakata"},{"id":"grammar","label":"Grammar"},{"id":"latihan","label":"Latihan"},{"id":"test","label":"Test"}]$lb$::jsonb,$lb$[{"text":"Memperkenalkan diri: はじめまして・よろしく","section":"dialog"},{"text":"Pola 〜は〜です (X adalah Y)","section":"grammar"},{"text":"Bertanya dengan か dan menjawab はい/いいえ","section":"grammar"},{"text":"Menyebut kebangsaan (〜人) & pekerjaan","section":"vocab"}]$lb$::jsonb,$lb$["hajimemashite","watashi","desu","amerikajin","nihonjin","kaishain","gakusei","onegaishimasu"]$lb$::jsonb,$lb$[{"type":"grammar_point","title":"〜は〜です — X adalah Y","body":"Pola kalimat paling dasar bahasa Jepang. Topik ditandai partikel は, lalu diakhiri です yang berfungsi seperti \"adalah\". Urutannya selalu [topik] は [keterangan] です.","pattern":"[topik] は [keterangan] です","example":{"tokens":[{"ref":"watashi"},{"ref":"ha"},{"ref":"gakusei"},{"ref":"desu"},{"text":"。"}],"translation":"Saya (adalah) mahasiswa."}},{"type":"grammar_point","title":"Partikel か — membuat pertanyaan","body":"Tambahkan か di akhir kalimat untuk menjadikannya pertanyaan — tidak perlu membalik urutan kata. Jawab dengan はい (ya) atau いいえ (tidak).","pattern":"[kalimat] です か。","example":{"tokens":[{"ref":"tanaka"},{"ref":"san"},{"ref":"ha"},{"ref":"kaishain"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Apakah Tanaka pegawai kantor?"}},{"type":"grammar_point","title":"〜人 — kebangsaan","body":"Gabungkan nama negara dengan 人 (jin) untuk menyebut kewarganegaraan. Pola ini sangat teratur dan langsung dipakai sebagai predikat dengan です.","table":{"columns":["Negara","Orang","Arti"],"rows":[[{"text":"日本"},{"tokens":[{"ref":"nihonjin"}]},{"text":"orang Jepang"}],[{"text":"アメリカ"},{"tokens":[{"ref":"amerikajin"}]},{"text":"orang Amerika"}],[{"text":"インドネシア"},{"tokens":[{"ref":"indoneshiajin"}]},{"text":"orang Indonesia"}]]}},{"type":"grammar_point","title":"Partikel の — kepemilikan & keterangan","body":"の menyambung dua nomina: yang di depan menerangkan yang di belakang. Bisa berarti \"milik\" (私の名前 = namaku) atau menerangkan asal/jenis (アメリカ人の学生 = mahasiswa dari Amerika).","pattern":"[nomina A] の [nomina B]","example":{"tokens":[{"ref":"amerikajin"},{"ref":"no"},{"ref":"gakusei"}],"translation":"mahasiswa dari Amerika"}}]$lb$::jsonb,$lb$[{"type":"mc","q":"アンナさんはどこの国の人ですか。","qTrans":"Anna berasal dari negara mana?","opts":["アメリカ","日本","インドネシア"],"ans":0,"expl":"「アメリカ人の学生です」 — Anna orang Amerika."},{"type":"mc","q":"田中さんの仕事は何ですか。","qTrans":"Apa pekerjaan Tanaka?","opts":["学生","会社員","先生"],"ans":1,"expl":"「会社員です」 — Tanaka pegawai kantor."},{"type":"fill","q":"私 ___ 学生です。","qTrans":"Pilih partikel yang tepat","opts":["は","を","か"],"ans":0,"expl":"は menandai topik kalimat: 私は = \"saya (topik)\"."},{"type":"fill","q":"田中さんは会社員です ___ 。","qTrans":"Jadikan pertanyaan","opts":["か","は","の"],"ans":0,"expl":"か di akhir kalimat menjadikannya pertanyaan."},{"type":"match","qTrans":"Jodohkan kata dengan artinya","pairs":[["会社員","pegawai kantor"],["学生","mahasiswa"],["日本人","orang Jepang"],["名前","nama"]]},{"type":"order","qTrans":"Susun jadi kalimat: \"Saya orang Amerika.\"","words":["私","は","アメリカ人","です","。"],"expl":"私 (topik) + は + アメリカ人 (predikat) + です."},{"type":"order","qTrans":"Susun jadi kalimat: \"Apakah Anda mahasiswa?\"","words":["あなた","は","学生","です","か","。"],"expl":"Kalimat pernyataan + か di akhir = pertanyaan."}]$lb$::jsonb,$lb$[{"q":"「はじめまして」 diucapkan saat…","opts":["Pertama kali bertemu","Berpisah","Makan malam"],"ans":0,"topic":"Salam kenalan"},{"q":"Partikel penanda topik adalah…","opts":["を","は","か"],"ans":1,"topic":"Partikel は"},{"q":"Untuk membuat pertanyaan, tambahkan…","opts":["か","の","です"],"ans":0,"topic":"Partikel か"},{"q":"「アメリカ人」 artinya…","opts":["Orang Jepang","Orang Amerika","Orang Indonesia"],"ans":1,"topic":"Kebangsaan 〜人"},{"q":"「私 ___ 名前」 — partikel milik yang tepat…","opts":["の","は","を"],"ans":0,"topic":"Partikel の"}]$lb$::jsonb,$lb$[{"ai":"こんにちは。はじめまして。お名前は？","trans":"Halo. Salam kenal. Siapa nama Anda?","choices":[{"t":"はじめまして。私は…です。","tr":"Salam kenal. Saya … ."},{"t":"こんにちは。よろしくお願いします。","tr":"Halo. Mohon bantuannya."}]},{"ai":"そうですか。学生ですか。","trans":"Oh begitu. Anda mahasiswa?","choices":[{"t":"はい、学生です。","tr":"Ya, saya mahasiswa."},{"t":"いいえ、会社員です。","tr":"Bukan, saya pegawai kantor."}]},{"ai":"どうぞよろしくお願いします。","trans":"Mohon bantuannya, ya.","choices":null}]$lb$::jsonb,0,true from public.lingbook_books b where b.slug='hajime-no-ippo'
on conflict (book_id,slug) do update set label=excluded.label,title=excluded.title,subtitle=excluded.subtitle,meta=excluded.meta,glossary=excluded.glossary,blocks=excluded.blocks,steps=excluded.steps,objectives=excluded.objectives,vocab_refs=excluded.vocab_refs,grammar_points=excluded.grammar_points,exercises=excluded.exercises,test=excluded.test,roleplay=excluded.roleplay,sort=excluded.sort,published=excluded.published;

-- bab: kaimono (買い物)
insert into public.lingbook_chapters (book_id,slug,label,title,subtitle,meta,glossary,blocks,steps,objectives,vocab_refs,grammar_points,exercises,test,roleplay,sort,published) select b.id,'kaimono','Unit 2 — 買い物','買い物','Berbelanja','± 9 menit · dialog + 4 grammar points + latihan',$lb${"sumimasen":{"surface":"すみません","romaji":"sumimasen","meaning":"permisi; maaf","pos":"ungkapan","grammar":{"Fungsi":"menyapa staf / meminta perhatian sopan"}},"kore":{"surface":"これ","romaji":"kore","meaning":"ini (benda dekat pembicara)","pos":"pronomina","grammar":{"Jenis":"kata tunjuk (ko-so-a-do)","Jarak":"dekat pembicara","Peran":"topik"}},"sore":{"surface":"それ","romaji":"sore","meaning":"itu (benda dekat lawan bicara)","pos":"pronomina","grammar":{"Jenis":"kata tunjuk","Jarak":"dekat lawan bicara"}},"are":{"surface":"あれ","romaji":"are","meaning":"itu (benda jauh dari keduanya)","pos":"pronomina","grammar":{"Jenis":"kata tunjuk","Jarak":"jauh dari pembicara & lawan bicara"}},"ha":{"surface":"は","romaji":"wa","meaning":"penanda topik","pos":"partikel","grammar":{"Fungsi":"menandai topik kalimat","Catatan":"ditulis は, dibaca \"wa\"","Kalimat ini":"menandai benda yang ditanyakan"}},"ikura":{"surface":"いくら","romaji":"ikura","meaning":"berapa (harga)","pos":"pronomina","grammar":{"Jenis":"kata tanya harga","Pola":"〜はいくらですか","Peran":"predikat tanya"}},"desu":{"surface":"です","romaji":"desu","meaning":"kopula sopan (\"adalah\")","pos":"kopula","grammar":{"Fungsi":"mengakhiri kalimat dengan sopan","Bentuk":"non-lampau · positif"},"forms":[{"form":"でした","note":"lampau"},{"form":"じゃありません","note":"negatif sopan"}]},"ka":{"surface":"か","romaji":"ka","meaning":"partikel tanya","pos":"partikel","grammar":{"Fungsi":"mengubah kalimat menjadi pertanyaan","Catatan":"menggantikan tanda tanya"}},"tshatsu":{"surface":"Tシャツ","romaji":"T-shatsu","meaning":"kaus; T-shirt","pos":"nomina","grammar":{"Jenis":"kata serapan (katakana)","Peran":"objek / predikat"}},"happyaku":{"surface":"八百","reading":"はっぴゃく","romaji":"happyaku","meaning":"delapan ratus (800)","pos":"numeralia","grammar":{"Catatan":"baca tak beraturan: 八 + 百 → はっぴゃく"}},"en":{"surface":"円","reading":"えん","romaji":"en","meaning":"yen (mata uang Jepang)","pos":"nomina","grammar":{"Pola":"[angka] + 円","Peran":"satuan harga"}},"jaa":{"surface":"じゃあ","romaji":"jā","meaning":"kalau begitu; baiklah","pos":"konjungsi","grammar":{"Fungsi":"peralihan topik / mengambil keputusan"}},"kaban":{"surface":"かばん","romaji":"kaban","meaning":"tas","pos":"nomina","grammar":{"Peran":"objek / predikat"}},"sengohyaku":{"surface":"千五百","reading":"せんごひゃく","romaji":"sen-gohyaku","meaning":"seribu lima ratus (1.500)","pos":"numeralia","grammar":{"Susunan":"千 (1000) + 五百 (500)"}},"chotto":{"surface":"ちょっと","romaji":"chotto","meaning":"sedikit; agak","pos":"adverbia","grammar":{"Fungsi":"memperhalus / meredam pernyataan","Nuansa":"「ちょっと高い」 = agak mahal (halus)"}},"takai":{"surface":"高い","reading":"たかい","romaji":"takai","meaning":"mahal; tinggi","pos":"adjektiva","grammar":{"Jenis":"adjektiva-i","Lawan":"安い (murah)","Peran":"predikat"},"forms":[{"form":"高くない","note":"negatif"},{"form":"高かった","note":"lampau"}]},"yasui":{"surface":"安い","reading":"やすい","romaji":"yasui","meaning":"murah","pos":"adjektiva","grammar":{"Jenis":"adjektiva-i","Lawan":"高い (mahal)","Peran":"predikat"},"forms":[{"form":"安くない","note":"negatif"},{"form":"安かった","note":"lampau"}]},"ne":{"surface":"ね","romaji":"ne","meaning":"ya kan; ya (mencari persetujuan)","pos":"partikel","grammar":{"Fungsi":"partikel akhir — mengajak setuju / berbagi perasaan"}},"wo":{"surface":"を","romaji":"o","meaning":"penanda objek langsung","pos":"partikel","grammar":{"Fungsi":"menandai objek dari verba","Catatan":"ditulis を, dibaca \"o\"","Kalimat ini":"menandai benda yang diminta"}},"kudasai":{"surface":"ください","romaji":"kudasai","meaning":"tolong (berikan)","pos":"ungkapan","grammar":{"Pola":"[nomina] をください = \"minta ~\"","Tingkat sopan":"netral-sopan"}},"arigatougozaimasu":{"surface":"ありがとうございます","romaji":"arigatō gozaimasu","meaning":"terima kasih (sopan)","pos":"ungkapan","grammar":{"Tingkat sopan":"sopan","Konteks":"diucapkan staf kepada pelanggan"}},"irasshaimase":{"surface":"いらっしゃいませ","romaji":"irasshaimase","meaning":"\"Selamat datang\" (di toko)","pos":"ungkapan","grammar":{"Konteks":"diucapkan staf kepada pelanggan"}},"nan":{"surface":"何","reading":"なん","romaji":"nan","meaning":"apa","pos":"pronomina","grammar":{"Jenis":"kata tanya","Peran":"predikat tanya"}},"hyaku":{"surface":"百","reading":"ひゃく","romaji":"hyaku","meaning":"seratus (100)","pos":"numeralia"},"sanbyaku":{"surface":"三百","reading":"さんびゃく","romaji":"sanbyaku","meaning":"tiga ratus (300)","pos":"numeralia","grammar":{"Catatan":"baca tak beraturan: 三 + 百 → さんびゃく"}},"roppyaku":{"surface":"六百","reading":"ろっぴゃく","romaji":"roppyaku","meaning":"enam ratus (600)","pos":"numeralia","grammar":{"Catatan":"baca tak beraturan: 六 + 百 → ろっぴゃく"}},"sen":{"surface":"千","reading":"せん","romaji":"sen","meaning":"seribu (1.000)","pos":"numeralia"},"kimono":{"surface":"着物","reading":"きもの","romaji":"kimono","meaning":"kimono (busana tradisional)","pos":"nomina","grammar":{"Jenis":"nama benda budaya"}},"anna":{"surface":"アンナ","romaji":"Anna","meaning":"Anna (nama orang)","pos":"nomina","grammar":{"Jenis":"nama diri (katakana)"}},"san":{"surface":"さん","romaji":"-san","meaning":"sufiks hormat untuk nama","pos":"sufiks","grammar":{"Fungsi":"panggilan sopan, netral gender"}},"to":{"surface":"と","romaji":"to","meaning":"dan (menghubungkan nomina)","pos":"partikel","grammar":{"Fungsi":"menghubungkan dua nomina","Kalimat ini":"menghubungkan かばん dan Tシャツ"}},"mimasu":{"surface":"見ます","reading":"みます","romaji":"mimasu","meaning":"melihat","pos":"verba","grammar":{"Bentuk kamus":"見る (miru)","Golongan":"Ichidan · Gol. II","Konjugasi":"non-lampau · positif · sopan (〜ます)"},"forms":[{"form":"見ない","note":"negatif kasual"},{"form":"見ました","note":"lampau"},{"form":"見て","note":"bentuk-te"}]}}$lb$::jsonb,$lb$[{"type":"heading","text":"会話の前に","sub":"Sebelum Percakapan"},{"type":"paragraph","tokens":[{"ref":"anna"},{"ref":"san"},{"ref":"ha"},{"ref":"kaban"},{"ref":"to"},{"ref":"tshatsu"},{"ref":"wo"},{"ref":"mimasu"},{"text":"。"},{"ref":"kaban"},{"ref":"ha"},{"ref":"chotto"},{"ref":"takai"},{"ref":"desu"},{"text":"。"}],"translation":"Anna melihat-lihat tas dan kaus. Tasnya agak mahal."},{"type":"heading","text":"会話","sub":"Percakapan"},{"type":"dialog","audioSrc":"/audio/lingbook/ja/kaimono/dialog.mp3","lines":[{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"sumimasen"},{"text":"。"},{"ref":"kore"},{"ref":"ha"},{"ref":"ikura"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Permisi. Ini berapa harganya?","audioSrc":"/audio/lingbook/ja/kaimono/l1.mp3"},{"speaker":"店員","role":"Pelayan","color":"#11313A","tokens":[{"ref":"sore"},{"ref":"ha"},{"ref":"tshatsu"},{"ref":"desu"},{"text":"。"},{"ref":"happyaku"},{"ref":"en"},{"ref":"desu"},{"text":"。"}],"translation":"Itu kaus. Harganya 800 yen.","audioSrc":"/audio/lingbook/ja/kaimono/l2.mp3"},{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"jaa"},{"text":"、"},{"ref":"are"},{"ref":"ha"},{"ref":"ikura"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Kalau begitu, yang itu berapa?","audioSrc":"/audio/lingbook/ja/kaimono/l3.mp3"},{"speaker":"店員","role":"Pelayan","color":"#11313A","tokens":[{"ref":"are"},{"ref":"ha"},{"ref":"kaban"},{"ref":"desu"},{"text":"。"},{"ref":"sengohyaku"},{"ref":"en"},{"ref":"desu"},{"text":"。"},{"ref":"chotto"},{"ref":"takai"},{"ref":"desu"},{"ref":"ne"},{"text":"。"}],"translation":"Yang itu tas. 1.500 yen. Agak mahal, ya.","audioSrc":"/audio/lingbook/ja/kaimono/l4.mp3"},{"speaker":"アンナ","role":"Anna","color":"#1A9E9E","tokens":[{"ref":"jaa"},{"text":"、"},{"ref":"kore"},{"ref":"wo"},{"ref":"kudasai"},{"text":"。"}],"translation":"Kalau begitu, minta yang ini, ya.","audioSrc":"/audio/lingbook/ja/kaimono/l5.mp3"},{"speaker":"店員","role":"Pelayan","color":"#11313A","tokens":[{"ref":"arigatougozaimasu"},{"text":"。"},{"ref":"happyaku"},{"ref":"en"},{"ref":"desu"},{"text":"。"}],"translation":"Terima kasih. 800 yen.","audioSrc":"/audio/lingbook/ja/kaimono/l6.mp3"}]},{"type":"audio","title":"Percakapan lengkap — kecepatan natural","src":"/audio/lingbook/ja/kaimono/full.mp3","durationSec":30,"transcript":[{"name":"Anna","tokens":[{"ref":"sumimasen"},{"text":"。"},{"ref":"kore"},{"ref":"ha"},{"ref":"ikura"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}]},{"name":"Pelayan","tokens":[{"ref":"sore"},{"ref":"ha"},{"ref":"tshatsu"},{"ref":"desu"},{"text":"。"},{"ref":"happyaku"},{"ref":"en"},{"ref":"desu"},{"text":"。"}]},{"name":"Anna","tokens":[{"ref":"jaa"},{"text":"、"},{"ref":"are"},{"ref":"ha"},{"ref":"ikura"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}]},{"name":"Pelayan","tokens":[{"ref":"are"},{"ref":"ha"},{"ref":"kaban"},{"ref":"desu"},{"text":"。"},{"ref":"sengohyaku"},{"ref":"en"},{"ref":"desu"},{"text":"。"}]}]},{"type":"culture_note","title":"Budaya: 税込 (harga sudah termasuk pajak) & トレー","body":"Di Jepang harga yang tertera biasanya sudah termasuk pajak (税込・zeikomi) dan tidak ada tawar-menawar di toko biasa. Saat membayar, letakkan uang di baki kecil (トレー) di kasir, bukan langsung ke tangan petugas."}]$lb$::jsonb,$lb$[{"id":"tujuan","label":"Tujuan"},{"id":"dialog","label":"Dialog"},{"id":"vocab","label":"Kosakata"},{"id":"grammar","label":"Grammar"},{"id":"latihan","label":"Latihan"},{"id":"test","label":"Test"}]$lb$::jsonb,$lb$[{"text":"Menanyakan harga: 〜はいくらですか","section":"dialog"},{"text":"Kata tunjuk これ・それ・あれ","section":"grammar"},{"text":"Membaca angka & harga dalam 円 (yen)","section":"grammar"},{"text":"Adjektiva-i 高い・安い (mahal/murah)","section":"vocab"}]$lb$::jsonb,$lb$["kore","sore","are","ikura","en","takai","yasui","kudasai"]$lb$::jsonb,$lb$[{"type":"grammar_point","title":"これ・それ・あれ — kata tunjuk benda","body":"Ketiganya menunjuk benda berdasarkan jarak: これ untuk benda dekat pembicara, それ dekat lawan bicara, dan あれ jauh dari keduanya. Dipakai sebagai topik dengan は.","pattern":"これ / それ / あれ + は … です","example":{"tokens":[{"ref":"kore"},{"ref":"ha"},{"ref":"tshatsu"},{"ref":"desu"},{"text":"。"}],"translation":"Ini (adalah) kaus."}},{"type":"grammar_point","title":"〜はいくらですか — menanyakan harga","body":"Untuk menanyakan harga, sebut bendanya + はいくらですか。 いくら khusus untuk menanyakan jumlah uang. Jawabannya berupa angka + 円 + です。","pattern":"[benda] は いくら です か。","example":{"tokens":[{"ref":"kore"},{"ref":"ha"},{"ref":"ikura"},{"ref":"desu"},{"ref":"ka"},{"text":"。"}],"translation":"Ini berapa harganya?"}},{"type":"grammar_point","title":"Angka & 円 — harga dalam yen","body":"Harga = angka + 円 (en). Ratusan memakai 百 (hyaku) dan ribuan memakai 千 (sen). Perhatikan tiga bacaan tak beraturan: 三百 (さんびゃく), 六百 (ろっぴゃく), dan 八百 (はっぴゃく).","table":{"columns":["Angka","Jepang","Baca"],"rows":[[{"text":"100"},{"tokens":[{"ref":"hyaku"}]},{"text":"hyaku"}],[{"text":"300"},{"tokens":[{"ref":"sanbyaku"}]},{"text":"san-byaku ⚠"}],[{"text":"600"},{"tokens":[{"ref":"roppyaku"}]},{"text":"rop-pyaku ⚠"}],[{"text":"800"},{"tokens":[{"ref":"happyaku"}]},{"text":"hap-pyaku ⚠"}],[{"text":"1.000"},{"tokens":[{"ref":"sen"}]},{"text":"sen"}],[{"text":"1.500"},{"tokens":[{"ref":"sengohyaku"}]},{"text":"sen-gohyaku"}]]}},{"type":"grammar_point","title":"高い・安い — adjektiva-i untuk harga","body":"高い berarti \"mahal\" (juga \"tinggi\") dan 安い berarti \"murah\". Keduanya adjektiva-i: langsung diikuti です tanpa partikel. Tambahkan ちょっと di depan untuk memperhalus (\"agak mahal\").","pattern":"[benda] は (ちょっと) 高い / 安い です","example":{"tokens":[{"ref":"are"},{"ref":"ha"},{"ref":"chotto"},{"ref":"takai"},{"ref":"desu"},{"text":"。"}],"translation":"Yang itu agak mahal."}}]$lb$::jsonb,$lb$[{"type":"mc","q":"Tシャツはいくらですか。","qTrans":"Berapa harga kaus itu?","opts":["八百円","千五百円","三百円"],"ans":0,"expl":"「Tシャツです。八百円です」 — kaus 800 yen."},{"type":"mc","q":"あれは何ですか。","qTrans":"Benda jauh itu apa?","opts":["Tシャツ","かばん","着物"],"ans":1,"expl":"「あれはかばんです」 — あれ menunjuk tas yang jauh."},{"type":"fill","q":"これ ___ いくらですか。","qTrans":"Pilih partikel yang tepat","opts":["は","を","の"],"ans":0,"expl":"は menandai topik: これは = \"ini (topik)\"."},{"type":"fill","q":"これ ___ ください。","qTrans":"Pilih partikel yang tepat","opts":["を","は","か"],"ans":0,"expl":"を menandai objek yang diminta pada pola 〜をください."},{"type":"match","qTrans":"Jodohkan kata dengan artinya","pairs":[["これ","ini"],["いくら","berapa (harga)"],["高い","mahal"],["円","yen"]]},{"type":"order","qTrans":"Susun jadi kalimat: \"Ini berapa harganya?\"","words":["これ","は","いくら","です","か","。"],"expl":"これ (topik) + は + いくら + です + か → pertanyaan harga."},{"type":"order","qTrans":"Susun jadi kalimat: \"Minta yang ini, ya.\"","words":["これ","を","ください","。"],"expl":"Pola 〜をください: objek dulu, lalu を, lalu ください."}]$lb$::jsonb,$lb$[{"q":"「いくら」 dipakai untuk menanyakan…","opts":["Harga","Waktu","Tempat"],"ans":0,"topic":"Menanyakan harga"},{"q":"Kata tunjuk untuk benda dekat pembicara adalah…","opts":["これ","それ","あれ"],"ans":0,"topic":"これ・それ・あれ"},{"q":"「高い」 artinya…","opts":["Murah","Mahal","Baru"],"ans":1,"topic":"Adjektiva 高い・安い"},{"q":"八百円 dibaca…","opts":["はっぴゃくえん","はちひゃくえん","はちえん"],"ans":0,"topic":"Angka & 円"},{"q":"これ ___ ください。 — partikel yang tepat…","opts":["を","は","か"],"ans":0,"topic":"Partikel を"}]$lb$::jsonb,$lb$[{"ai":"いらっしゃいませ。","trans":"Selamat datang.","choices":[{"t":"すみません、これはいくらですか。","tr":"Permisi, ini berapa?"},{"t":"あれはいくらですか。","tr":"Yang itu berapa?"}]},{"ai":"それは八百円です。","trans":"Itu 800 yen.","choices":[{"t":"じゃあ、これをください。","tr":"Kalau begitu, minta ini."},{"t":"ちょっと高いですね。","tr":"Agak mahal, ya."}]},{"ai":"ありがとうございます。","trans":"Terima kasih banyak.","choices":null}]$lb$::jsonb,1,true from public.lingbook_books b where b.slug='hajime-no-ippo'
