-- bab: en-el-cafe (En el café)
insert into public.lingbook_chapters (book_id,slug,label,title,subtitle,meta,glossary,blocks,steps,objectives,vocab_refs,grammar_points,exercises,test,roleplay,sort,published) select b.id,'en-el-cafe','Unit 3 — En el café','En el café','Di Kafe','± 10 menit · versi ringkas (validasi language-agnostic)',$lb${"hoy":{"surface":"Hoy","meaning":"hari ini","pos":"adverbia","grammar":{"Jenis":"adverbia waktu"}},"yukiE":{"surface":"Yuki","meaning":"Yuki (nama orang)","pos":"nomina","grammar":{"Jenis":"nama diri"}},"rinaE":{"surface":"Rina","meaning":"Rina (nama orang)","pos":"nomina","grammar":{"Jenis":"nama diri"}},"y":{"surface":"y","meaning":"dan","pos":"konjungsi","grammar":{"Fungsi":"menghubungkan dua unsur setara"}},"van":{"surface":"van","meaning":"(mereka) pergi","pos":"verba","grammar":{"Infinitivo":"ir — tidak beraturan","Konjugasi":"presente · 3 jamak (ellos/ellas)","Peran":"predikat"},"forms":[{"form":"voy","note":"yo"},{"form":"vas","note":"tú"},{"form":"va","note":"él / ella"}]},"a":{"surface":"a","meaning":"ke","pos":"preposisi","grammar":{"Fungsi":"arah / tujuan"}},"un":{"surface":"un","meaning":"sebuah (maskulin)","pos":"artikel","grammar":{"Jenis":"artikel tak tentu maskulin","Pasangan feminin":"una"}},"cafeE":{"surface":"café","meaning":"kopi; kafe","pos":"nomina","grammar":{"Gender":"maskulin","Jumlah":"tunggal","Peran":"objek"}},"en":{"surface":"en","meaning":"di","pos":"preposisi","grammar":{"Fungsi":"lokasi"}},"madrid":{"surface":"Madrid","meaning":"Madrid (kota)","pos":"nomina","grammar":{"Jenis":"nama tempat"}},"les":{"surface":"Les","meaning":"kepada mereka","pos":"pronomina","grammar":{"Jenis":"pronomina objek tak langsung","Pola":"gustar → les gusta"}},"gusta":{"surface":"gusta","meaning":"disukai (oleh)","pos":"verba","grammar":{"Infinitivo":"gustar","Konjugasi":"presente · 3 tunggal","Pola":"subjek = hal yang disukai","Peran":"predikat"},"forms":[{"form":"gustan","note":"subjek jamak"},{"form":"gustó","note":"lampau"}]},"mucho":{"surface":"mucho","meaning":"sangat; banyak","pos":"adverbia","grammar":{"Posisi":"setelah verba"}},"el":{"surface":"el","meaning":"artikel tentu maskulin","pos":"artikel","grammar":{"Jenis":"artikel tentu maskulin","Pasangan feminin":"la"}},"hola":{"surface":"Hola","meaning":"halo","pos":"ungkapan","grammar":{"Konteks":"sapaan universal, kasual-sopan"}},"que":{"surface":"Qué","meaning":"apa","pos":"pronomina","grammar":{"Jenis":"kata tanya","Catatan":"aksen é membedakan dari \"que\""}},"desean":{"surface":"desean","meaning":"(Anda sekalian) ingin","pos":"verba","grammar":{"Infinitivo":"desear","Konjugasi":"presente · ustedes (sopan jamak)","Register":"sopan, khas pelayan"},"forms":[{"form":"deseo","note":"yo"},{"form":"deseas","note":"tú"}]},"tomar":{"surface":"tomar","meaning":"minum; mengambil","pos":"verba","grammar":{"Bentuk":"infinitivo","Peran":"pelengkap dari desean"}},"quiero":{"surface":"Quiero","meaning":"(saya) ingin","pos":"verba","grammar":{"Infinitivo":"querer","Perubahan akar":"e → ie","Konjugasi":"presente · 1 tunggal (yo)","Peran":"predikat"},"forms":[{"form":"quieres","note":"tú"},{"form":"quiere","note":"él / ella"},{"form":"queremos","note":"nosotros"}]},"con":{"surface":"con","meaning":"dengan","pos":"preposisi","grammar":{"Frasa":"café con leche = kopi susu"}},"leche":{"surface":"leche","meaning":"susu","pos":"nomina","grammar":{"Gender":"feminin","Frasa":"café con leche"}},"porfavor":{"surface":"por favor","meaning":"tolong; silakan","pos":"ungkapan","grammar":{"Register":"sopan universal"}},"para":{"surface":"Para","meaning":"untuk","pos":"preposisi","grammar":{"Frasa":"para mí = \"untuk saya\""}},"mi":{"surface":"mí","meaning":"saya (setelah preposisi)","pos":"pronomina","grammar":{"Bentuk":"pronomina preposisional","Catatan":"aksen í membedakan dari \"mi\" (milikku)"}},"teE":{"surface":"té","meaning":"teh","pos":"nomina","grammar":{"Gender":"maskulin","Catatan":"aksen é membedakan dari \"te\" (kamu)"}},"verde":{"surface":"verde","meaning":"hijau","pos":"adjektiva","grammar":{"Posisi":"setelah nomina","Bentuk":"sama untuk maskulin / feminin"}},"perfecto":{"surface":"Perfecto","meaning":"sempurna; siap","pos":"ungkapan","grammar":{"Konteks":"konfirmasi antusias"}},"ahora":{"surface":"Ahora","meaning":"sekarang","pos":"adverbia","grammar":{"Frasa":"ahora mismo = \"segera\""}},"mismo":{"surface":"mismo","meaning":"juga; tepat","pos":"adverbia","grammar":{"Frasa":"ahora mismo = \"segera\""}},"quieres":{"surface":"quieres","meaning":"(kamu) ingin","pos":"verba","grammar":{"Infinitivo":"querer","Konjugasi":"presente · 2 tunggal (tú)"}},"quiere":{"surface":"quiere","meaning":"(dia) ingin","pos":"verba","grammar":{"Infinitivo":"querer","Konjugasi":"presente · 3 tunggal"}},"queremos":{"surface":"queremos","meaning":"(kami) ingin","pos":"verba","grammar":{"Infinitivo":"querer","Konjugasi":"presente · 1 jamak","Catatan":"akar tidak berubah pada nosotros"}}}$lb$::jsonb,$lb$[{"type":"heading","text":"El diálogo","sub":"Percakapan"},{"type":"paragraph","tokens":[{"ref":"hoy"},{"text":","},{"ref":"yukiE"},{"ref":"y"},{"ref":"rinaE"},{"ref":"van"},{"ref":"a"},{"ref":"un"},{"ref":"cafeE"},{"ref":"en"},{"ref":"madrid"},{"text":"."},{"ref":"les"},{"ref":"gusta"},{"ref":"mucho"},{"ref":"el"},{"ref":"cafeE"},{"text":"."}],"translation":"Hari ini, Yuki dan Rina pergi ke sebuah kafe di Madrid. Mereka sangat suka kopi."},{"type":"callout","variant":"info","title":"Artikel & gender","body":"Setiap nomina Spanyol punya gender. Artikelnya mengikuti: un / el (maskulin), una / la (feminin). café bergender maskulin → un café."},{"type":"dialog","audioSrc":"/audio/lingbook/es/en-el-cafe/dialog.mp3","lines":[{"speaker":"Camarero","role":"Pelayan","color":"#11313A","tokens":[{"text":"¡"},{"ref":"hola"},{"text":"!"},{"text":"¿"},{"ref":"que"},{"ref":"desean"},{"ref":"tomar"},{"text":"?"}],"translation":"Halo! Mau minum apa?"},{"speaker":"Rina","role":"Siswa","color":"#1A9E9E","tokens":[{"ref":"quiero"},{"ref":"un"},{"ref":"cafeE"},{"ref":"con"},{"ref":"leche"},{"text":","},{"ref":"porfavor"},{"text":"."}],"translation":"Saya mau kopi susu, ya."},{"speaker":"Yuki","role":"Siswa","color":"#7A5FC0","tokens":[{"ref":"para"},{"ref":"mi"},{"text":","},{"ref":"un"},{"ref":"teE"},{"ref":"verde"},{"text":"."}],"translation":"Untuk saya, teh hijau."},{"speaker":"Camarero","role":"Pelayan","color":"#11313A","tokens":[{"text":"¡"},{"ref":"perfecto"},{"text":"!"},{"ref":"ahora"},{"ref":"mismo"},{"text":"."}],"translation":"Siap! Segera datang."}]},{"type":"table","title":"Conjugación: querer (presente)","columns":["Subjek","Bentuk","Arti"],"rows":[[{"text":"yo"},{"tokens":[{"ref":"quiero"}]},{"text":"saya ingin"}],[{"text":"tú"},{"tokens":[{"ref":"quieres"}]},{"text":"kamu ingin"}],[{"text":"él / ella"},{"tokens":[{"ref":"quiere"}]},{"text":"dia ingin"}],[{"text":"nosotros"},{"tokens":[{"ref":"queremos"}]},{"text":"kami ingin"}]]}]$lb$::jsonb,$lb$[{"id":"tujuan","label":"Tujuan"},{"id":"dialog","label":"Dialog"},{"id":"vocab","label":"Kosakata"}]$lb$::jsonb,$lb$[{"text":"Memesan minuman di kafe","section":"dialog"},{"text":"Artikel & gender (un/una, el/la)","section":"dialog"},{"text":"Verba querer (presente)","section":"vocab"}]$lb$::jsonb,$lb$["cafeE","leche","teE","quiero","tomar","porfavor"]$lb$::jsonb,$lb$[]$lb$::jsonb,$lb$[]$lb$::jsonb,$lb$[]$lb$::jsonb,$lb$[]$lb$::jsonb,0,true from public.lingbook_books b where b.slug='paso-a-paso'
